INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 7001, 0.0, 0.0, 0, 1, 106001, 7, 1, 0, "たまには\n協力するのもいいんじゃない？\nあたしも手を貸してあげる", "キャル", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 7002, 0.0, 0.0, 0, 1, 105901, 7, 1, 0, "多くの方と協力して\n戦えるようです\n主さまなら、さぞ\nご活躍なさることでしょう", "コッコロ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 7003, 0.0, 0.0, 0, 1, 105801, 7, 1, 0, "たくさんの人と一緒に\n協力バトルです！\nがんばりましょう☆", "ペコリーヌ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 10001, 0.0, 0.0, 0, 1, 105801, 10, 1, 0, "ジュエルを食べ物…\nいえ、貴重品と交換できます！", "ペコリーヌ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 10002, 0.0, 0.0, 0, 1, 106001, 10, 1, 0, "ジュエルはよく考えて\n使うことね\n無駄遣い厳禁！", "キャル", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 10003, 0.0, 0.0, 0, 1, 105901, 10, 1, 0, "主さまのジュエルで\n貴重な品々を購入できます\nですが、無駄遣いは\n『めっ』でございますよ", "コッコロ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 2, 10004, 0.0, 0.0, 0, 1, 106401, 10, 1, 2104010, "ジュエルがあれば\n貴重品と交換できるみたい\n大事に使いましょうね", "シェフィ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-416.5, 1, 12001, 0.0, 0.0, 0, 1, 105801, 12, 1, 0, "特定の条件を達成すると\n報酬がもらえますよ！\nがんばりましょう♪　", "ペコリーヌ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 13001, 0.0, 0.0, 0, 1, 106001, 13, 1, 0, "思い出が詰まってるって\nいろいろあったけど\n振り返るのもいいんじゃない？", "キャル", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 13002, 0.0, 0.0, 0, 1, 105901, 13, 1, 0, "主さまとの楽しい日々…\nこちらで何度でも\n思い返しましょう♪", "コッコロ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 2, 13003, 0.0, 0.0, 0, 1, 106401, 13, 1, 2104010, "みんなとの大切な思い出が\nたくさん詰まってるのね\n一緒に振り返って、\n心に刻みたいわ", "シェフィ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 13004, 0.0, 0.0, 0, 1, 105801, 13, 1, 0, "女の子との思い出が\nたくさん見られますよ！\nヒューヒュー♪\nモテモテですねー☆", "ペコリーヌ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 14001, 0.0, 0.0, 0, 1, 105901, 14, 1, 0, "育成に必要なアイテムが\n獲得できるクエストです\nわたくし、主さまのために、\n強くなりますよ", "コッコロ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 2, 14002, 0.0, 0.0, 0, 1, 106401, 14, 1, 2104010, "このクエストを攻略すると、\nアイテムが手に入るらしいわ。\nもっと強くなるために、\n一生懸命がんばるわね！", "シェフィ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 14003, 0.0, 0.0, 0, 1, 105801, 14, 1, 0, "このクエストを攻略すれば、\nアイテムがもらえますよ\nたくさん集めて、どんどん\n強くなっちゃいましょう！", "ペコリーヌ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 14004, 0.0, 0.0, 0, 1, 106001, 14, 1, 0, "クエストを攻略すると、\nアイテムが手に入るんだって\nもらえるものは、\nもらっておきましょ！", "キャル", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-470.0, 1, 15001, 0.0, 0.0, 0, 1, 105901, 15, 1, 0, "主さま、旅の準備を整えて\nより充実した冒険をいたし\nましょう", "コッコロ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 2, 16001, 0.0, 0.0, 0, 1, 106401, 16, 1, 2104010, "ねぇ…クランに加入してみない？\n一人も楽しいけど、みんなと\n一緒も賑やかでいいと思うの", "シェフィ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 16002, 0.0, 0.0, 0, 1, 105801, 16, 1, 0, "クランに加入してみませんか？\nみんなといっしょに冒険した方が、\n楽しいですよ！", "ペコリーヌ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 16003, 0.0, 0.0, 0, 1, 106001, 16, 1, 0, "クランに入れるらしいわよ\nせっかくだから入ってみたら？\nけっこう楽しいみたいよ♪", "キャル", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 16004, 0.0, 0.0, 0, 1, 105901, 16, 1, 0, "こちらでクランに加入できます\n素敵なクランがたくさんあって、\n目移りしてしまいますね", "コッコロ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 17002, 0.0, 0.0, 0, 1, 105901, 17, 1, 0, " こちらではクランバトルに\n 参加された仲間のみなさんの\n 活躍を振り返ることができます", "コッコロ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 17004, 0.0, 0.0, 0, 1, 106001, 25, 1, 0, "模擬戦の戦績もアンタが\n気に入ったものがあれば\n記録しておけるのね", "キャル", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 17005, 0.0, 0.0, 0, 1, 105901, 25, 1, 0, "主さま、今回のクランバトルでの\nご活躍が記録されています\nバトルの参考にいたしましょう", "コッコロ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 2, 17006, 0.0, 0.0, 0, 1, 106401, 25, 1, 2104010, "今回のクランバトルの調子は\nどうかしら？\n戦績を見れば、次のバトルに\n活かせるかもしれないわ", "シェフィ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 17007, 0.0, 0.0, 0, 1, 105801, 25, 1, 0, "今回のクランバトルでの戦績を\nおさらいできますよ！\n私にも見せてください☆", "ペコリーヌ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 18001, 0.0, 0.0, 0, 1, 190801, 18, 1, 0, "ようこそ！\nこちらでは、\nギルドハウスで流れる音楽の\n変更や購入が出来ますよ", "カリン", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 18002, 0.0, 0.0, 0, 2, 190801, 18, 1, 0, "ＢＧＭの変更や購入は、こちらから\nできますよ\n素敵な音楽を、たくさんご用意\nいたしました！", "カリン", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-470.0, 1, 19001, 0.0, 0.0, 0, 3, 190801, 19, 1, 0, "ギルドハウスの\nＢＧＭを変更できますよ\nあなたの好きな曲、\n私にも聴かせてくださいね", "カリン", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-470.0, 1, 19002, 0.0, 0.0, 0, 4, 190801, 19, 1, 0, "こちらでは、ＢＧＭの変更が\nできますよ\nどんな曲に変更しますか？\nふふふ、私も楽しみです♪", "カリン", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-470.0, 1, 20001, 0.0, 0.0, 0, 5, 190801, 20, 1, 0, "こちらでは、ＢＧＭを購入\nすることができますよ\n試聴することもできるので、\nじっくり選んでくださいね", "カリン", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-470.0, 1, 20002, 0.0, 0.0, 0, 6, 190801, 20, 1, 0, "いらっしゃいませ！\nＢＧＭの購入はこちらです\n素敵な曲がたくさんあって、\n目移りしちゃいますね", "カリン", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 21001, 0.0, 0.0, 0, 1, 106001, 21, 1, 0, "ここで手に入れたアイテムで\n専用装備を作成できるみたいね\nアイテムが集まったら\nさっそく作ってみましょ！", "キャル", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 21002, 0.0, 0.0, 0, 1, 105901, 21, 1, 0, "攻略すると珍しいアイテムが\n手に入りますよ\nこのアイテムで専用装備を\n作成できるようです", "コッコロ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 2, 21003, 0.0, 0.0, 0, 1, 106401, 21, 1, 2104010, "専用装備が欲しいなら\nこのクエストに挑戦するといいわ\n集めた素材でもっともっと\n強くなりましょう", "シェフィ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 21004, 0.0, 0.0, 0, 1, 105801, 21, 1, 0, "専用装備の作成に必要な\nアイテムを獲得できますよ\nたくさん集めてどんどん\n強くなりましょう！", "ペコリーヌ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-430.0, 1, 22001, 0.0, 0.0, 0, 1, 190801, 22, 1, 0, "投票はこちらです\nあなたが応援したい女の子に\n思いを込めた一票を\nお願いします！", "カリン", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-430.0, 1, 22002, 0.0, 0.0, 0, 2, 190801, 22, 1, 0, "ようこそ！\nあなたが思いを寄せるのは\nどの女の子ですか？\n応援してあげてくださいね！", "カリン", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-430.0, 1, 23001, 0.0, 0.0, 0, 3, 190801, 23, 1, 0, "たくさんの投票、\nありがとうございました\n結果発表を楽しみに\n待っていてくださいね！", "カリン", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-430.0, 1, 23002, 0.0, 0.0, 0, 4, 190801, 23, 1, 0, "ただ今、人気投票の\n集計中です\n結果が出るまでもう少しだけ\nお待ちくださいね", "カリン", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-385.0, 1, 24001, 4.08, 8.0, 10011, 1, 109001, 24, 2, 0, "あなた様が手伝ってくださった\nチョコレートケーキ\n美味しくないはずがありませんわ", "エリコ（バレンタイン）", "2019/01/31 12:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-385.0, 1, 24002, 5.0, 8.0, 10011, 2, 109001, 24, 2, 0, "このような失敗、あなた様が\nするはずありません\nもう一度挑戦してみましょう", "エリコ（バレンタイン）", "2019/01/31 12:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-385.0, 1, 24003, 10.11, 8.0, 10011, 3, 109001, 24, 2, 0, "あなた様のために\n作っているケーキを\nあなた様に手伝っていただく……\nことになるなんて……クスクス", "エリコ（バレンタイン）", "2019/01/31 12:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-385.0, 1, 24004, 4.0, 8.0, 10011, 4, 109001, 24, 2, 0, "あまり気に病む必要はありませんわ\nこれからは私がたっぷりと\n時間をかけて教えて差し上げますから", "エリコ（バレンタイン）", "2019/01/31 12:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-385.0, 1, 24005, 6.0, 8.0, 10011, 5, 109001, 24, 2, 0, "今回は調子が悪かった……のですか？\nあなた様が手伝ってくれたものなら\nわたしはどんなものでも……クスクス", "エリコ（バレンタイン）", "2019/01/31 12:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 1, 24006, 0.0, 0.0, 10011, 6, 109002, 24, 1, 0, "あなた様が手がけた\nチョコレートケーキは\n私にとっての宝物……\n侮辱する者は生かしておきませんわ", "エリコ（バレンタイン）", "2019/01/31 12:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 1, 24007, 0.0, 0.0, 10011, 7, 109002, 24, 1, 0, "とても素晴らしい出来栄えですわ！\nあなた様にふさわしい\nチョコレートケーキができました", "エリコ（バレンタイン）", "2019/01/31 12:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 1, 24008, 0.0, 0.0, 10011, 8, 109002, 24, 1, 0, "私を手伝ってくれたあなた様は\nすでに私の虜……\n甘い世界に誘って差し上げますわ", "エリコ（バレンタイン）", "2019/01/31 12:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 1, 24009, 0.0, 0.0, 10011, 9, 109002, 24, 1, 0, "あなた様の愛情\nしかと受け止めました\nこれが……私たちの初めての\n共同作業ですわね……クスクス", "エリコ（バレンタイン）", "2019/01/31 12:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 1, 24010, 0.0, 0.0, 10011, 10, 109002, 24, 1, 0, "これは世界一の\nチョコレートケーキですわ\nだって、あなた様が腕によりをかけて\n作ってくださったんですもの", "エリコ（バレンタイン）", "2019/01/31 12:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-385.0, 1, 24011, 2.12, 8.0, 10011, 1, 109101, 24, 2, 0, "上手にできなくて残念だった？\nでも、弟くんの気持ちが嬉しいな\nいつだってお姉ちゃんは\nそばにいるからね♪", "シズル（バレンタイン）", "2019/01/31 12:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-385.0, 5, 24012, 4.19, 8.0, 10011, 2, 109101, 24, 2, 0, "うーん、弟くんには珍しく\n緊張しちゃったのかな？\nもう一度チャレンジしてみる？", "シズル（バレンタイン）", "2019/01/31 12:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-385.0, 2, 24013, 2.3, 8.0, 10011, 3, 109101, 24, 4, 0, "お姉ちゃんのお手伝い、\nよくできました！\nあー、\nまだつまみ食いしちゃダメだぞ！", "シズル（バレンタイン）", "2019/01/31 12:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 1, 24014, 0.0, 0.0, 10011, 4, 109102, 24, 1, 0, "見てみて！\nスポンジに綺麗な焼き目がついてるよ\nさっすが弟くんだね！", "シズル（バレンタイン）", "2019/01/31 12:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-385.0, 5, 24015, 5.23, 8.0, 10011, 5, 109101, 24, 2, 0, "まぁまぁ、落ち込まないで\n見た目は……個性的だけど、\n味は絶対美味しいはずだから！", "シズル（バレンタイン）", "2019/01/31 12:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 1, 24016, 0.0, 0.0, 10011, 6, 109102, 24, 1, 0, "弟くんみたいな\n可愛いケーキができたよ！\n早く食べてみたいでしょ♪", "シズル（バレンタイン）", "2019/01/31 12:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-385.0, 1, 24017, 5.01, 8.0, 10011, 7, 109101, 24, 2, 0, "あれれ？　弟くん、指に\nチョコレートがくっついてるよ？\nお姉ちゃんが舐めてあげるね、\nはぁむ！", "シズル（バレンタイン）", "2019/01/31 12:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 1, 24018, 0.0, 0.0, 10011, 8, 109102, 24, 1, 0, "なかなか上手にできたんじゃない？\nでも弟くんはまだまだできる子！\nお姉ちゃん、信じてるからね", "シズル（バレンタイン）", "2019/01/31 12:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 1, 24019, 0.0, 0.0, 10011, 9, 109102, 24, 1, 0, "わぁ～、\nとっても美味しそうにできたね！\n弟くん手慣れてたから\nお姉ちゃん安心して任せられちゃった！", "シズル（バレンタイン）", "2019/01/31 12:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 1, 24020, 0.0, 0.0, 10011, 10, 109102, 24, 1, 0, "や～ん、弟くんが手伝ってくれた\nチョコレートケーキ！\nすっごく美味しそうにできたね♪", "シズル（バレンタイン）", "2019/01/31 12:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 2, 26001, 0.0, 0.0, 0, 1, 106401, 26, 1, 2104010, "ここから先は神聖な場所みたい\nどんなお宝が眠っているのか、\n今から探索するのが楽しみね♪", "シェフィ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 26002, 0.0, 0.0, 0, 1, 105801, 26, 1, 0, "ここから先は神聖な場所\nみたいです！\nどんなお宝が手に入るか\n楽しみですね！", "ペコリーヌ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 26003, 0.0, 0.0, 0, 1, 106001, 26, 1, 0, "この先は神聖な場所みたい。\n手に入るお宝も並じゃないけど\n気を付けていかないと\n痛い目にあうわよ", "キャル", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 26004, 0.0, 0.0, 0, 1, 105901, 26, 1, 0, "ここから先は神聖な場所\nでございます。\n気を引き締めてお宝の\n調査探索に参りましょう", "コッコロ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 2, 27001, 0.0, 0.0, 0, 1, 106401, 27, 1, 2104010, "ここにさらなる力を得るための\nアイテムが眠っている…って\nみんな言ってるわ。ふふっ、\nそれじゃあ挑戦してみましょうか", "シェフィ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 27002, 0.0, 0.0, 0, 1, 105801, 27, 1, 0, "ここにさらなる力を得るための\nアイテムが眠っているみたい\nです！　どこから挑戦するか\n迷っちゃいますね！", "ペコリーヌ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 27003, 0.0, 0.0, 0, 1, 106001, 27, 1, 0, "ここにさらなる力を得るための\nアイテムが眠っているみたい！\nどんどん挑戦して\n強くなっちゃいましょ！", "キャル", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 27004, 0.0, 0.0, 0, 1, 105901, 27, 1, 0, "こちらにさらなる力を得る\nためのアイテムが眠っている\nようです。主さま、どこから\n挑戦いたしましょう。", "コッコロ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 28001, 0.0, 0.0, 0, 1, 190801, 28, 1, 0, "ようこそ！\n皆さんの素敵な出会いを\nギルド管理協会が\nお手伝いします！", "カリン", "2019/09/24 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 28002, 0.0, 0.0, 0, 2, 190801, 28, 1, 0, "ギルド管理協会です\nフレンドに関しては\nこちらでご確認ください", "カリン", "2019/09/24 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-409.0, 1, 29001, 0.0, 0.0, 0, 3, 190801, 29, 1, 0, "こちらがフレンドの\n皆さんです\n素敵な関係を\n築いてくださいね！", "カリン", "2019/09/24 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-409.0, 1, 29002, 0.0, 0.0, 0, 4, 190801, 29, 1, 0, "こちらの一覧で\nフレンドのプロフィールを\n確認できますよ", "カリン", "2019/09/24 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-409.0, 1, 30001, 0.0, 0.0, 0, 5, 190801, 30, 1, 0, "フレンド管理は\nこちらになります\n新しいフレンドとの出会いを\n楽しんでくださいね！", "カリン", "2019/09/24 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-409.0, 1, 30002, 0.0, 0.0, 0, 6, 190801, 30, 1, 0, "フレンドの申請や\n承認ができますよ\nどうぞ、良き交流を！", "カリン", "2019/09/24 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-409.0, 1, 31001, 0.0, 0.0, 0, 7, 190801, 31, 1, 0, "バトルをして力比べを\nしてみましょう！\n実力が試されますね、\n頑張ってください！", "カリン", "2019/10/31 12:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-409.0, 1, 31002, 0.0, 0.0, 0, 8, 190801, 31, 1, 0, "気になるパーティと\nバトルをしてみましょう！\nどちらが勝利するのか、\n私も楽しみにしていますね", "カリン", "2019/10/31 12:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-409.0, 1, 32001, 0.0, 0.0, 0, 1, 190801, 32, 1, 0, "ルーキーの皆さんのために\n特別なミッションを\nご用意いたしました！\nぜひ、挑戦してください！", "カリン", "2019/12/20 5:00:00", "2020/01/04 4:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-409.0, 1, 32002, 0.0, 0.0, 0, 2, 190801, 32, 1, 0, "期間限定のキャンペーンを\n開催中です！\nミッションにチャレンジ\nしましょう！", "カリン", "2019/12/20 5:00:00", "2020/01/04 4:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-409.0, 1, 33001, 0.0, 0.0, 0, 3, 190801, 33, 1, 0, "フレンドになって\n初心者の方を応援しましょう！\n素敵な報酬が待っていますよ！", "カリン", "2019/12/20 5:00:00", "2020/01/04 4:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-409.0, 1, 33002, 0.0, 0.0, 0, 4, 190801, 33, 1, 0, "期間限定のキャンペーンを\n開催中です！\nミッションにチャレンジ\nしましょう！", "カリン", "2019/12/20 5:00:00", "2020/01/04 4:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-409.0, 1, 34001, 0.0, 0.0, 0, 5, 190801, 34, 1, 0, "お疲れ様でした！\nミッションの報酬の受け取りは\nこちらからできますよ！", "カリン", "2020/01/04 5:00:00", "2020/01/10 11:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-409.0, 1, 34002, 0.0, 0.0, 0, 6, 190801, 34, 1, 0, "ミッション報酬の受け取りは\nこちら！\n受け取り漏れの無いように\n気を付けてくださいね！", "カリン", "2020/01/04 5:00:00", "2020/01/10 11:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-458.0, 1, 38001, 5.3, 0.0, 0, 1, 105801, 38, 2, 0, "過去のストーリーイベントを\n楽しめちゃいますよ！\n遊んだことのないものがあれば\n一緒にやってみましょう♪", "ペコリーヌ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-458.0, 1, 38002, 6.5, 0.0, 0, 2, 105801, 38, 2, 0, "これまでのイベントで登場した\n限定キャラを仲間にできたり\nメモリーピースが手に入る\nみたいですよ。やばいですね☆", "ペコリーヌ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (9999.0, 3, 39005, 0.0, 9999.0, 0, 0, 105801, 39, 3, 0, "", "ペコリーヌ", "2020/04/01", "2020/04/08 23:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-430.0, 1, 40001, 0.0, 0.0, 0, 2, 190801, 40, 1, 0, "これまでに出題された\n問題を振り返ることが\nできますよ\n復習は大切です♪", "カリン", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 41001, 0.0, 0.0, 0, 1, 106401, 41, 1, 2104010, "ここでは腕試しが\nできるんですって。\n自分の実力を測るのに、\nちょうどよさそうね。", "シェフィ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 41002, 0.0, 0.0, 0, 1, 105801, 41, 1, 0, "ここで腕試しを\nしていきましょう！\n全力全開、\nがんばっちゃいますよ～！", "ペコリーヌ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 41003, 0.0, 0.0, 0, 1, 106001, 41, 1, 0, "ここで腕試しが\nできるみたいね。\n試してみるのも\nいいんじゃない？", "キャル", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 41004, 0.0, 0.0, 0, 1, 105901, 41, 1, 0, "腕試しができるようです。\nここで練習を重ね、実戦に\n活かしてまいりましょう。", "コッコロ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-416.5, 1, 42001, 0.0, 0.0, 0, 1, 105901, 42, 1, 0, "訓練の成果に応じて、\n報酬がもらえるそうです。\n共に励んでいきましょう。", "コッコロ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-416.5, 1, 42002, 0.0, 0.0, 0, 1, 106401, 42, 1, 2104010, "目標を達成すれば、\n報酬がもらえるみたい。\n頑張り甲斐があるわね。", "シェフィ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-416.5, 1, 42003, 0.0, 0.0, 0, 1, 105801, 42, 1, 0, "腕試しをがんばれば、\n報酬がもらえますよ。\n挑戦していきましょう☆", "ペコリーヌ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-416.5, 1, 42004, 0.0, 0.0, 0, 1, 106001, 42, 1, 0, "ミッションを達成すると、\n報酬が出るんですって。\n一緒にやってみましょ！", "キャル", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 43001, 0.0, 0.0, 0, 1, 105801, 43, 1, 0, "ここからアリーナに\n挑戦できますよ！\n編成を工夫してライバルに\n挑んじゃいましょう！", "ペコリーヌ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 43002, 0.0, 0.0, 0, 1, 105901, 43, 1, 0, "こちらからアリーナに\n挑戦することができます。\n主さまらしい編成で\nライバルに挑みましょう。", "コッコロ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-363.0, 1, 43003, 0.0, 0.0, 0, 1, 106001, 43, 1, 0, "ここからアリーナに\n挑戦できるわよ！\nしっかり編成を考えて\nライバルに挑みなさい！", "キャル", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-416.5, 1, 43004, 0.0, 0.0, 0, 1, 123001, 44, 1, 0, "ミッションをクリアすると報酬が\n受け取れるわ。ジャンジャン\nクリアしてバリバリ強化して\nあげなさい♪", "アメス", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-416.5, 1, 43005, 0.0, 0.0, 0, 2, 123001, 44, 1, 0, "ぼんやりしてる場合じゃないわ。\n早くミッションをクリアして\n報酬を受け取ってきなさい！", "アメス", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-416.5, 1, 43006, 5.79, 0.0, 0, 3, 123001, 45, 2, 0, "ちょっとあんた、報酬が\n受け取れるじゃない！\n忘れずにチェックなさい。\nアメス様との約束よ？", "アメス", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-371.5, 1, 46001, 0.0, 0.0, 0, 1, 123001, 46, 1, 0, "はい、お疲れさま。\nここではマスタリーチケットを\n使って、マスタリー強化素材を\n手に入れることができるわよ。", "アメス", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-416.5, 2, 47001, 0.0, 0.0, 0, 1, 104901, 47, 2, 0, "呼ばれて飛び出てお姉ちゃんだよ♪\nたとえ火の中、水の中、迷宮の中っ\nこのダンジョンを踏破できるよう\n弟くんを応援してあげるからねっ♪", "シズル", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-416.5, 1, 47002, 9.32, 0.0, 0, 1, 101101, 47, 2, 0, "ほんとーに不思議な場所ですね～\nお兄ちゃんが冒険を頑張れるよう\nおまじないをかけてあげますねっ\nフレーフレー、お・兄・ちゃんっ♪", "リノ", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (-470.0, 2, 48001, 0.0, 0.0, 0, 0, 104901, 48, 2, 0, "", "シズル", "2015/12/17 15:00:00", "2030/12/17 14:59:59");
